import { render, html } from 'lit';
import { unsafeHTML } from 'lit/directives/unsafe-html.js';

export interface TooltipMixinOptions {
  /**
   * ID of the global tooltip element to use
   * @default 'global-tooltip'
   */
  tooltipId?: string;
  /**
   * Css class selector for the tooltip HTML content within the trigger
   * @default 'tooltip-content'
   */
  tooltipHtmlContentSelector?: string;
  /**
   * Container element to search for tooltip elements (supports Shadow DOM)
   * @default document
   */
  container?: Document | ShadowRoot | HTMLElement;
}

// Fixed attribute names that cannot be changed
const ACTIVATED_ATTRIBUTE = 'data-tooltip';
const CONTENT_ATTRIBUTE = 'data-tooltip-content';
const APPEARANCE_ATTRIBUTE = 'data-tooltip-appearance';

const DEFAULT_OPTIONS = {
  tooltipId: 'global-tooltip',
  tooltipHtmlContentSelector: 'tooltip-html-content',
  container: typeof document !== 'undefined' ? (document as Document | ShadowRoot | HTMLElement) : undefined,
};

let initialized = false;
let currentOptions: typeof DEFAULT_OPTIONS = DEFAULT_OPTIONS;
let tooltipElement: HTMLElement | null = null;
let tooltipTriggerElements: NodeListOf<HTMLElement> | null = null;

/**
 * Initialize the tooltip mixin system
 * Sets up event delegation for tooltip or popover triggers
 */
export function initTooltipMixin(options: TooltipMixinOptions = {}): void {
  if (initialized) {
    return;
  }

  currentOptions = { ...DEFAULT_OPTIONS, ...options };

  // Ensure the global tooltip exists
  const container = currentOptions.container;

  if (!container) {
    return;
  }
  tooltipElement =
    container instanceof Document
      ? container.getElementById(currentOptions.tooltipId)
      : container.querySelector(`#${currentOptions.tooltipId}`);

  if (
    !tooltipElement ||
    (tooltipElement.tagName.toLowerCase() !== 'mc-tooltip' && tooltipElement.tagName.toLowerCase() !== 'mc-popover')
  ) {
    console.error(
      `TooltipMixin: No mc-tooltip element found with id="${currentOptions.tooltipId}". ` +
        `Please add <mc-tooltip id="${currentOptions.tooltipId}"></mc-tooltip> to your page.`,
    );
    return;
  }

  setupTooltips();

  initialized = true;
}

/**
 * Destroy the tooltip mixin system and clean up event listeners
 */
export function destroyTooltipMixin(): void {
  if (!initialized) {
    return;
  }

  cleanupEventListeners();

  initialized = false;
}

// ========== Internal Functions ==========

function setupTooltips(): void {
  const container = currentOptions.container;
  if (!container) {
    return;
  }
  tooltipTriggerElements = container.querySelectorAll(`[${ACTIVATED_ATTRIBUTE}]`);

  if (tooltipTriggerElements.length > 0) {
    tooltipTriggerElements.forEach((el) => {
      setupEventListeners(el);
      const contentElement = el.querySelector(`.${currentOptions.tooltipHtmlContentSelector}`) as HTMLElement;
      if (contentElement) {
        contentElement.style.display = 'none';
      }
    });
  }
}

function setupEventListeners(el: HTMLElement): void {
  if (el) {
    el.addEventListener('mouseover', handleShow);
    el.addEventListener('focusin', handleShow);
  }
}

function cleanupEventListeners(): void {
  if (tooltipTriggerElements) {
    tooltipTriggerElements.forEach((el) => {
      el.removeEventListener('mouseover', handleShow);
      el.removeEventListener('focusin', handleShow);
    });
  }
}

function handleShow(event: Event): void {
  const triggerEl = event.target as HTMLElement;

  if (!triggerEl || !tooltipElement) {
    return;
  }

  let content: string | HTMLElement | null = null;
  let isHtmlContent = false;
  const contentElement = triggerEl.querySelector(`.${currentOptions.tooltipHtmlContentSelector}`) as HTMLElement;
  if (contentElement) {
    isHtmlContent = true;
    content = contentElement;
  } else {
    content = triggerEl.getAttribute(CONTENT_ATTRIBUTE);
  }

  if (!content) {
    return;
  }

  if ((tooltipElement as any).customtriggerelement !== triggerEl) {
    (tooltipElement as any).customtriggerelement = triggerEl;

    const appearance = triggerEl.getAttribute(APPEARANCE_ATTRIBUTE);
    (tooltipElement as any).appearance = appearance || 'neutral-default';

    let tooltipInnerSpan = tooltipElement.querySelector('span');
    if (!tooltipInnerSpan) {
      tooltipInnerSpan = document.createElement('span');
      tooltipInnerSpan.classList.add(currentOptions.tooltipHtmlContentSelector);
      tooltipElement.appendChild(tooltipInnerSpan);
    }

    if (isHtmlContent && content instanceof HTMLElement) {
      const clonedContent = content.cloneNode(true) as HTMLElement;
      clonedContent.style.display = '';
      render(html`${unsafeHTML(clonedContent.innerHTML)}`, tooltipInnerSpan);
    } else if (typeof content === 'string') {
      render(html`${content}`, tooltipInnerSpan);
    }
    requestAnimationFrame(() => {
      const syntheticEvent = new MouseEvent('mouseover', {
        bubbles: true,
        cancelable: true,
        view: window,
        relatedTarget: null,
      });
      triggerEl.dispatchEvent(syntheticEvent);
    });
  }
}
